/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWProdutoReceita-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&ProRef.IsEmpty() AND &ProNom.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Ref.Cód.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&ProRef) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(&ProNom) EndIf
If not (&ProTipDef.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Def.") If Not &ProTipDef.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &ProTipDef.EnumerationDescription() Endif EndIf
If not (&ProTipCus.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Custo") If Not &ProTipCus.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &ProTipCus.EnumerationDescription() Endif EndIf
If not (&ProSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Status") If Not &ProSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &ProSts.EnumerationDescription() Endif EndIf
If not (&ProStsRec.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Receitas") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = '' do Case Case &ProStsRec.ToString().Trim() = "S" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Válida"
Case &ProStsRec.ToString().Trim() = "N" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Inválida"
EndCase EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Ref.Cód." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Descrição" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "UND" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Tipo de Custo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Definição" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Total Receita" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Auto Alimentar"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod ProNom when &OrderedBy = 1 order ProRef when &OrderedBy = 2 AND &OrderedDsc = False order (ProRef) when &OrderedBy = 2 AND &OrderedDsc = True order ProNom when &OrderedBy = 3 AND &OrderedDsc = False order (ProNom) when &OrderedBy = 3 AND &OrderedDsc = True order ProEmbUnd when &OrderedBy = 4 AND &OrderedDsc = False order (ProEmbUnd) when &OrderedBy = 4 AND &OrderedDsc = True order ProTipCus when &OrderedBy = 5 AND &OrderedDsc = False order (ProTipCus) when &OrderedBy = 5 AND &OrderedDsc = True order ProTipDef when &OrderedBy = 6 AND &OrderedDsc = False order (ProTipDef) when &OrderedBy = 6 AND &OrderedDsc = True order ProAtuEst when &OrderedBy = 7 AND &OrderedDsc = False order (ProAtuEst) when &OrderedBy = 7 AND &OrderedDsc = True
using DSWWProdutoReceita(&ProRef, &ProNom, &ProTipDef, &ProTipCus, &ProSts, &ProStsRec)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(ProRef) &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(ProNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(ProEmbUnd) &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = ProTipCus.EnumerationDescription() If Not ProTipDef.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = ProTipDef.EnumerationDescription() Endif &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Number = ProVlrCusRec &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = ProAtuEst.ToString()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWProdutoReceitaGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWProdutoReceitaGridState")) Else &GridState.FromXml(&Session.Get(!"WWProdutoReceitaGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PROREF" &ProRef.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PRONOM" &ProNom.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROTIPDEF" &ProTipDef.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROTIPCUS" &ProTipCus.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROSTS" &ProSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROSTSREC" &ProStsRec.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

